-- ========== next_sequence RPC 함수 (이미 존재하면 교체) ==========
CREATE OR REPLACE FUNCTION next_sequence(seq_key TEXT)
RETURNS INTEGER AS $$
DECLARE
  next_val INTEGER;
BEGIN
  VALUES (seq_key, 1, NOW())
  ON CONFLICT (key) DO UPDATE SET current_value = sequences.current_value + 1, updated_at = NOW()
  RETURNING current_value INTO next_val;
  RETURN next_val;
END;
$$ LANGUAGE plpgsql;

-- ========== 회사 (companies) ==========
ON CONFLICT (id) DO NOTHING;

-- ========== 부서 (departments) - 기존 데이터 삭제 후 재입력 ==========
DELETE FROM departments WHERE company_id IN ('a0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000002');
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, default_folders = EXCLUDED.default_folders, updated_at = NOW();

